// Parse Input
// Safely extract the 'actions' field from whatever shape the caller sends
const inputData = $input.first().json;

const rawActions =
  (inputData.actions !== undefined && inputData.actions !== null)
    ? inputData.actions
    : (inputData.body && inputData.body.actions !== undefined ? inputData.body.actions : null);

return [{ json: { rawActions: rawActions !== null ? rawActions : '' } }];

// Parse Actions
const { rawActions } = $input.first().json;

let actions = [];

try {
  const parsed = typeof rawActions === 'string'
    ? JSON.parse(rawActions)
    : rawActions;

  if (Array.isArray(parsed)) {
    actions = parsed.filter(a => a && a.id);
  }
} catch (e) {
  actions = [];
}

return [{ json: { actions } }];

// Normalize Output
// Reads id from the paired Split Out item — no index-based matching
const rawText = String($input.item.json.text || $input.item.json.output || '').trim();

const fallback = 'Olá! Gostaria de retomar nossa conversa e alinhar os próximos passos.';

// Paired item access: resolves to the Split Out item that produced this LLM output
const originalAction = $('Split Out').item.json;
const id = String(originalAction.id || '');

if (!id) return;

const text = rawText.length > 0 ? rawText : fallback;
const mensagem = text.length > 500 ? text.substring(0, 497) + '...' : text;

return { json: { id, mensagem_pronta: mensagem } };
